import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.BOIfnwPZ.js";const h=JSON.parse('{"title":"Limitations","description":"","frontmatter":{},"headers":[],"relativePath":"implementation/limitations.md","filePath":"implementation/limitations.md","lastUpdated":1779359895000}'),o={name:"implementation/limitations.md"};function n(s,e,l,c,p,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h1><p>This page summarizes the current implementation limits of TORCH that are relevant when designing CRTDLs, configuring profile support, and interpreting extraction results.</p><h2 id="supported-fhir-version" tabindex="-1">Supported FHIR version <a class="header-anchor" href="#supported-fhir-version" aria-label="Permalink to &quot;Supported FHIR version&quot;">​</a></h2><p>TORCH currently supports <strong>FHIR R4</strong> only.</p><p>Other FHIR versions such as DSTU2 or R5 are not supported by the current implementation and documentation.</p><h2 id="profile-availability-at-startup" tabindex="-1">Profile availability at startup <a class="header-anchor" href="#profile-availability-at-startup" aria-label="Permalink to &quot;Profile availability at startup&quot;">​</a></h2><p>TORCH does not resolve arbitrary profiles on demand during extraction.</p><p>All relevant <code>StructureDefinition</code> resources must be made available at startup through configuration. If a CRTDL references a profile that is not available locally, validation fails.</p><p>This means TORCH currently supports only the profile set that is mounted or configured before the service starts.</p><p>In principle, FHIR resources can often be matched to a profile based on their content even without explicit profile metadata.</p><p>In practice, however, this kind of profile inference is expensive, can be ambiguous, and is difficult to make robust across heterogeneous real-world data.</p><p>For that reason, TORCH intentionally uses a claim-based profile model.</p><p>In practice, TORCH primarily works with declared profile claims, especially canonical profile URLs in the CRTDL and profile annotations on resources.</p><p>The canonical URL in the CRTDL must match a locally available <code>StructureDefinition</code>. Local file names or informal profile aliases are not sufficient. The canonical URL in the CRTDL must match a locally available StructureDefinition. Local file names or informal profile aliases are not sufficient. All StructureDefinitions are loaded at startup from the configured profile directory; profile loading is not dynamic and changes require a restart.</p><p>For the same practical reason, resources should also be annotated with their profile information, typically via <code>meta.profile</code>.</p><p>If resources are missing this annotation, TORCH has no information available to match them against the configured profile set, which prevents those resources from being processed. TORCH relies on profile constraints to retrieve resources via FHIR Search.</p><p>This also limits how far TORCH can rely on profile inheritance alone. If processing depends on a specific derived profile, that profile should be claimed explicitly rather than assumed only through inheritance relationships.</p><h2 id="terminology-backed-slicing" tabindex="-1">Terminology-backed slicing <a class="header-anchor" href="#terminology-backed-slicing" aria-label="Permalink to &quot;Terminology-backed slicing&quot;">​</a></h2><p>TORCH does not provide its own terminology service.</p><p>Because of that, slicing that depends on terminology expansion or value set membership is currently not supported.</p><p>In particular, value-set-based slice discrimination cannot be evaluated by TORCH alone.</p><h2 id="reference-format-restrictions" tabindex="-1">Reference format restrictions <a class="header-anchor" href="#reference-format-restrictions" aria-label="Permalink to &quot;Reference format restrictions&quot;">​</a></h2><p>TORCH expects resource references in the relative FHIR form <code>ResourceType/id</code>.</p><p>The current extraction implementation does not support:</p><ul><li>absolute references such as <code>https://example.org/fhir/Patient/123</code></li><li>URN references such as <code>urn:uuid:...</code></li><li>malformed references that do not match <code>ResourceType/id</code></li></ul><p>Unsupported references are rejected during parsing or ignored during grouping and resolution, depending on where they are encountered.</p><h2 id="nested-resource-handling" tabindex="-1">Nested resource handling <a class="header-anchor" href="#nested-resource-handling" aria-label="Permalink to &quot;Nested resource handling&quot;">​</a></h2><p>TORCH does not fully resolve deeply nested resource structures.</p><p>Nested content can be preserved as part of the extracted field, but it is not generally expanded into independently resolved substructures during extraction.</p><p>This matters especially for complex backbone elements or nested structures that would require deeper traversal than a direct attribute-based extraction path.</p><h2 id="validation-scope" tabindex="-1">Validation scope <a class="header-anchor" href="#validation-scope" aria-label="Permalink to &quot;Validation scope&quot;">​</a></h2><p>TORCH validates CRTDL structure, profile references, attributes, linked groups, and a number of technical requirements before extraction starts.</p><p>TORCH does not perform full profile conformance validation of extracted output resources.<br> This is a deliberate design decision based on its role in the data processing pipeline.</p><p>TORCH focuses on extracting, transforming, and preparing data for downstream use. In many scenarios, the extracted data is further processed, aggregated, or flattened rather than used as fully validated FHIR resources. As a result, strict end-of-pipeline profile validation would add significant overhead without providing proportional benefit.</p><p>Instead, TORCH ensures structural correctness during extraction and reconstruction and relies on upstream data quality and downstream validation steps where full profile conformance is required.</p><p>As a result, extraction is profile-aware, but TORCH should not be interpreted as a full profile validator.</p><h2 id="consent-model-boundaries" tabindex="-1">Consent model boundaries <a class="header-anchor" href="#consent-model-boundaries" aria-label="Permalink to &quot;Consent model boundaries&quot;">​</a></h2><p>Consent handling in TORCH is based on the consent rules expressed in the CRTDL and the resource mappings implemented in the application.</p><p>More complex consent models, institution-specific policy engines, or unsupported resource type mappings may require custom implementation work.</p><h2 id="interoperability-and-server-behavior" tabindex="-1">Interoperability and server behavior <a class="header-anchor" href="#interoperability-and-server-behavior" aria-label="Permalink to &quot;Interoperability and server behavior&quot;">​</a></h2><p>TORCH produces FHIR-based output and relies on standard FHIR server behavior where possible.</p><p>Even so, interoperability is not guaranteed across all vendor-specific FHIR implementations. Differences in search behavior, profile quality, reference consistency, and bulk export support can affect extraction results.</p><p>Large extractions are also constrained by the performance and feature set of the connected FHIR server.</p><h2 id="known-feature-gaps" tabindex="-1">Known feature gaps <a class="header-anchor" href="#known-feature-gaps" aria-label="Permalink to &quot;Known feature gaps&quot;">​</a></h2><p>The following capabilities are currently not available in TORCH:</p><ul><li>automatic extraction of modifiers</li><li>local blacklisting or whitelisting of selected element ids</li><li>full validation against profiles</li><li>value-set-based slicing support</li></ul><p>These areas should be considered current product limitations.</p>',47)])])}const f=a(o,[["render",n]]);export{h as __pageData,f as default};
